func (db *GlobalGormDB) GetAppTrigger(appID, networkID, templateID, agencyNetworkID int) (int, error) {
	var triggerID int
	err := db.db.Raw("SELECT id FROM kochava_postbacks.triggers WHERE app_id = ? AND filter_network = ? AND template_id = ? AND filter_agency_network = ?", appID, networkID, templateID, agencyNetworkID).Scan(&triggerID).Error
	if err != nil {
		return -1, err
	}
	return triggerID, nil
}

func (db *GlobalGormDB) InsertInstallTriggers(networkID int, appID int, templateID int, agencyNetworkID int) error {
	tx := db.db.Begin()
	err := tx.Exec("INSERT INTO kochava_postbacks.triggers (app_id, title, type, context, filter_network, filter_str, filter_agency_network, active, template_id, date_created) VALUES (?, '', 'install', '{}', ?, '', ?, 1, ?, ?)", appID, networkID, agencyNetworkID, templateID, time.Now().Unix()).Error
	if err != nil {
		tx.Rollback()
		return err
	}

	return tx.Commit().Error
}

func (db *GlobalGormDB) UpdateInstallTriggers(networkID int, appID int, templateID int, agencyNetworkID int) error {
	tx := db.db.Begin()
	err := tx.Exec("UPDATE kochava_postbacks.triggers SET filter_network = ?, filter_str = '', active = 1 WHERE app_id = ? AND template_id = ? AND type = 'install' AND filter_agency_network = ?", networkID, appID, templateID, agencyNetworkID).Error
	if err != nil {
		tx.Rollback()
		return err
	}

	return tx.Commit().Error
}

func (db *GlobalGormDB) InsertTriggers(appID int, templateID int, title, filterStr, typee string) error {
	tx := db.db.Begin()
	err := tx.Exec("INSERT INTO kochava_postbacks.triggers (app_id, title, type, context, filter_network, filter_str, active, template_id, date_created) VALUES (?, ?, ?, '{}', 0, ?, 0, ?, ?)", appID, title, typee, filterStr, templateID, time.Now().Unix()).Error
	if err != nil {
		tx.Rollback()
		return err
	}

	return tx.Commit().Error
}

