func (db *GlobalGormDB) GetNewTrigger(triggerID int64) ([]models.Trigger, error) {
	query := `SELECT id, app_id, active, type, filter_str, filter_network, filter_agency_network, title, template_id, active, date_created, context
				FROM kochava_postbacks.triggers
				WHERE id = ?
				LIMIT 1`
	var trigger []models.Trigger
	err := db.db.Exec(query, triggerID).Scan(&trigger).Error
	if err != nil {
		return nil, err
	}
	return trigger, nil
}

func (db *GlobalGormDB) GetTriggersWithAgency(whereParams map[string]any, agencyNetwork int) ([]models.Trigger, error) {
	var triggers []models.Trigger
	var whereParts []string
	var args []interface{}

	// Dynamically build whereStatement and args
	for key, value := range whereParams {
		whereParts = append(whereParts, fmt.Sprintf("%s = ?", key))
		args = append(args, value)
	}
	whereStatement := strings.Join(whereParts, " AND ")

	agencyWhereStatement := " AND (filter_agency_network = '-1' OR filter_agency_network = '0')"
	if agencyNetwork > 0 {
		agencyWhereStatement = " AND filter_agency_network = " + strconv.Itoa(agencyNetwork)
	}
	whereStatement += agencyWhereStatement

	rows, err := db.db.Table("kochava_postbacks.triggers").Select("id, app_id, active, type, filter_str, filter_network, filter_agency_network, title, template_id, date_created, context").Where(whereStatement, args...).Rows()
	if err != nil {
		clog.Error(context.Background(), "error querying triggers", zap.Error(err))
		return nil, err
	}
	defer func() {
		_ = rows.Close()
	}()
	for rows.Next() {
		var trigger models.Trigger
		var contextString string // Temporary variable to hold the context as a string
		err = rows.Scan(&trigger.ID, &trigger.AppID, &trigger.Active, &trigger.Type, &trigger.FilterStr, &trigger.FilterNetwork, &trigger.FilterAgencyNetwork, &trigger.Title, &trigger.TemplateID, &trigger.DateCreated, &contextString)
		if err != nil {
			clog.Error(context.Background(), "error scanning row", zap.Error(err))
			return nil, err
		}
		if contextString == "" {
			trigger.Context = map[string]interface{}{}
		} else {
			if err := json.Unmarshal([]byte(contextString), &trigger.Context); err != nil {
				clog.Error(context.Background(), "error unmarshaling context", zap.Error(err))
				return nil, err
			}
		}
		triggers = append(triggers, trigger)
	}
	if triggers == nil {
		triggers = []models.Trigger{}
	}
	return triggers, err
}

func (db *GlobalGormDB) FetchAgenciesByTrigger(ctx context.Context, appID string) ([]int, error) {
	query := `
		SELECT tpl.network_id
		FROM kochava_postbacks.triggers AS t
		LEFT JOIN kochava_postbacks.templates AS tpl ON tpl.id = t.template_id
		LEFT JOIN kochava.cpi_networks
			AS cn ON cn.id = tpl.network_id
		WHERE t.app_id = ? AND t.active = 1 AND tpl.type = 'install' AND cn.acl = 4
		GROUP BY t.template_id, t.filter_agency_network
		ORDER BY tpl.name ASC
	`
	var agenciesByTrigger []int
	err := db.db.Raw(query, appID).Scan(&agenciesByTrigger).Error
	return agenciesByTrigger, err
}

// FetchTriggers returns an app's install triggers, scoped by agency network.
//
// The caller (get_agency_triggers) passes the agency_network_ids it wants to view as
// ids. Each agency configures its own trigger row (same app_id/template_id, distinct
// filter_agency_network), so the scope MUST filter on filter_agency_network — not on
// filter_network. When no agency ids are supplied we fall back to the advertiser scope
// (filter_agency_network = 0). Without this, agency triggers exist in the triggers table
// but never come back to the UI, and switching agencies surfaces the wrong agency's rows.
func (db *GlobalGormDB) FetchTriggers(ctx context.Context, appID string, ids []string) ([]models.Trigger, error) {
	executeParams := []any{appID}

	// Sanitize the agency ids before scoping. Callers build ids via strings.Split, which
	// can yield empty/whitespace entries (e.g. a trailing comma). An empty string bound to
	// an INT comparison coerces to 0 in MySQL, which would pull advertiser-scoped rows
	// (filter_agency_network = 0) into an agency-scoped request and break isolation. Parse
	// each id to int and drop anything invalid so only real agency network IDs are matched.
	var placeholders []string
	for _, id := range ids {
		agencyID, err := strconv.Atoi(strings.TrimSpace(id))
		if err != nil {
			continue
		}
		placeholders = append(placeholders, "?")
		executeParams = append(executeParams, agencyID)
	}

	var agencyScope string
	if len(placeholders) > 0 {
		agencyScope = fmt.Sprintf("t.filter_agency_network IN (%s)", strings.Join(placeholders, ", "))
	} else {
		// No valid agency requested: advertiser-level triggers only.
		agencyScope = "t.filter_agency_network = 0"
	}

	query := fmt.Sprintf(`
		SELECT t.id, n.name, t.filter_network, t.title, t.template_id, t.active, t.filter_agency_network FROM kochava_postbacks.triggers t
		LEFT JOIN kochava.cpi_networks n ON n.id = t.filter_network
		WHERE t.app_id = ? AND t.type = 'install' AND t.filter_network != '' AND %s
	`, agencyScope)

	var triggers []models.Trigger
	err := db.db.Raw(query, executeParams...).Scan(&triggers).Error
	return triggers, err
}
