// TestGetAppTrigger_ScopedByAgencyNetwork guards the agency-postback regression:
// an advertiser-level trigger (filter_agency_network=0) and an agency-level trigger
// can share (app_id, filter_network, template_id). GetAppTrigger must only match
// within the requested agency scope, otherwise an agency create routes to
// UpdateInstallTriggers and overwrites the advertiser trigger.
func TestGetAppTrigger_ScopedByAgencyNetwork(t *testing.T) {
	globalDB, cleanup := setupTriggersTestDB(t)
	defer cleanup()

	// Seed trigger id=2 is advertiser-level: app=1000, network=100, template=2, agency=0.
	// Add an agency-level trigger for the same app/network/template, agency=777.
	err := globalDB.InsertInstallTriggers(100, 1000, 2, 777)
	require.NoError(t, err)

	// Advertiser scope finds the advertiser trigger.
	advID, err := globalDB.GetAppTrigger(1000, 100, 2, 0)
	require.NoError(t, err)
	assert.Equal(t, 2, advID, "advertiser scope should find the advertiser trigger")

	// Agency scope finds the agency trigger, NOT the advertiser one.
	agencyID, err := globalDB.GetAppTrigger(1000, 100, 2, 777)
	require.NoError(t, err)
	assert.NotEqual(t, 0, agencyID, "agency scope should find a trigger")
	assert.NotEqual(t, 2, agencyID, "agency scope must not match the advertiser trigger")

	// A scope with no matching trigger returns 0 (routes to InsertInstallTriggers).
	missID, err := globalDB.GetAppTrigger(1000, 100, 2, 999)
	require.NoError(t, err)
	assert.Equal(t, 0, missID, "unmatched agency scope should find nothing")
}

// TestUpdateInstallTriggers_DoesNotCorruptOtherScope is the core regression test for
// the reported escalation: creating an agency postback must not flip the advertiser
// trigger's filter_agency_network, which would hide it from the advertiser (FetchTriggers
// filters filter_agency_network=0) and make the postback show as Active.
func TestUpdateInstallTriggers_DoesNotCorruptOtherScope(t *testing.T) {
	globalDB, cleanup := setupTriggersTestDB(t)
	defer cleanup()

	// Add an agency-level trigger alongside the advertiser trigger (id=2, agency=0).
	err := globalDB.InsertInstallTriggers(100, 1000, 2, 777)
	require.NoError(t, err)

	// Simulate the agency create path updating its own scope.
	err = globalDB.UpdateInstallTriggers(100, 1000, 2, 777)
	require.NoError(t, err)

	// The advertiser trigger must be untouched: still agency=0, still visible.
	advTriggers, err := globalDB.GetPostbackTriggers(map[string]any{"id": 2}, "")
	require.NoError(t, err)
	require.Len(t, advTriggers, 1)
	assert.Equal(t, 0, advTriggers[0].FilterAgencyNetwork,
		"advertiser trigger filter_agency_network must remain 0 after an agency update")

	// And it remains discoverable via the advertiser-scoped FetchTriggers path.
	visible, err := globalDB.FetchTriggers(context.Background(), "1000", nil)
	require.NoError(t, err)
	found := false
	for _, tr := range visible {
		if tr.ID == 2 {
			found = true
		}
	}
	assert.True(t, found, "advertiser trigger must remain visible to FetchTriggers (filter_agency_network=0)")
