func (h *NewConfigHandler) handlePost(ctx context.Context, w http.ResponseWriter, r *http.Request, body models.NewPartnerConfiguration, appID string, accountID string) {
	var templateID int
	hasPipeline := false

	apiKey := r.Header.Get("Authentication-Key")
	if apiKey == "" {
		response.HandleError(ctx, w, http.StatusBadRequest, response.WarnLvl, "missing authentication key")
		return
	}

	appIDI, err := strconv.Atoi(appID)
	if err != nil {
		response.HandleError(ctx, w, http.StatusBadRequest, response.ErrorLvl, "Error converting app ID", zap.Error(err))
		return
	}

	switch body.Action {
	case "network":

		dbAppDAO := h.Base.AppDAO

		networkID, err := strconv.Atoi(body.NetworkPartner)
		if err != nil {
			response.HandleError(ctx, w, http.StatusBadRequest, response.ErrorLvl, "Error converting network ID", zap.Error(err))
			return
		}

		// Determine the effective type for template lookup
		// If create_for_agency is true, treat it as an agency configuration
		effectiveType := body.Type
		if body.CreateForAgency {
			effectiveType = "agency"
		}
		var agencyNetworkIDI int
		var template models.Template
		if effectiveType == "agency" {
			// For agency configurations, use the agency_network_id from the request body
			if body.AgencyNetworkId != "" {
				agencyNetworkIDI, err = strconv.Atoi(body.AgencyNetworkId)
				if err != nil {
					response.HandleError(ctx, w, http.StatusInternalServerError, response.ErrorLvl, "Failed to convert agency network ID from request", zap.Error(err))
					return
				}
			} else {
				response.HandleError(ctx, w, http.StatusBadRequest, response.ErrorLvl, "agency_network_id is required when create_for_agency is true")
				return
			}

			agencyNetwork, err := h.DB().GetNetworkInfo(networkID)
			if err != nil {
				response.HandleError(ctx, w, http.StatusInternalServerError, response.ErrorLvl, "Failed to get network info", zap.Error(err))
				return
			}

			templateID, err = h.DB().GetTemplateID(networkID)
			if err != nil {
				response.HandleError(ctx, w, http.StatusInternalServerError, response.ErrorLvl, "Failed to get template ID", zap.Error(err))
				return
			}

			// Convert the agency account ID from the network info to int
			agencyAccountID, err := strconv.Atoi(agencyNetwork.AccountID)
			if err != nil {
				response.HandleError(ctx, w, http.StatusInternalServerError, response.ErrorLvl, "Failed to convert agency account ID", zap.Error(err))
				return
			}

			err = h.DB().CheckAccountApps(appIDI, agencyAccountID)
			if err != nil {
				response.HandleError(ctx, w, http.StatusForbidden, response.ErrorLvl, "App configuration mismatch - account apps", zap.Error(err))
				return
			}
			if templateID == 0 {
				err = h.DB().InsertTemplate(networkID, agencyNetwork.Name)
				if err != nil {
					response.HandleError(ctx, w, http.StatusInternalServerError, response.ErrorLvl, "Failed to insert template", zap.Error(err))
					return
				}
				// After inserting, fetch the template ID again
				templateID, err = h.DB().GetTemplateID(networkID)
				if err != nil {
					response.HandleError(ctx, w, http.StatusInternalServerError, response.ErrorLvl, "Failed to get template ID after insert", zap.Error(err))
					return
				}
			}

			// For agency type, we already have the templateID, so fetch the template details
			if templateID != 0 {
				whereParams := map[string]any{"id": templateID}
				templates, err := h.DB().GetPostbackTemplates(whereParams, "1")
				if err != nil {
					response.HandleError(ctx, w, http.StatusInternalServerError, response.DebugLvl, "Failed to fetch template by ID", zap.Error(err))
					return
				}
				if len(templates) > 0 {
					template = templates[0]
				}
			}
		} else {
			// For non-agency types, look up template by network_id and type
			whereParams := map[string]any{"network_id": networkID, "type": effectiveType}
			templates, err := h.DB().GetPostbackTemplates(whereParams, "1")
			if err != nil {
				response.HandleError(ctx, w, http.StatusInternalServerError, response.DebugLvl, "Failed to fetch template by network ID and type", zap.Error(err))
				return
			}

			if len(templates) > 0 {
				template = templates[0]
				templateID = template.ID
			}
		}

		var posts []models.Post
		posts, err = dbAppDAO.GetPosts(appID, "", []string{"ko_cpi_campaign"}, []string{"publish"})
		if err != nil {
			response.HandleError(ctx, w, http.StatusInternalServerError, response.ErrorLvl, "Invalid install pipeline id for app", zap.Error(err))
