func (h *NewConfigHandler) fillNetwork(networkExtended models.NetworkExtended) models.NetworkConf {
	network := models.NetworkConf{
		Name:      networkExtended.Name,
		LogoURL:   networkExtended.LogoURL,
		Type:      networkExtended.Type,
		NetworkID: networkExtended.NetworkID,
		AccountID: networkExtended.AccountID,
	}
	return network
}

func freezeTrigger(input map[string]interface{}) Trigger {
	trigger := Trigger{}

	// Helper function to safely get string from map
	getString := func(key string) string {
		if val, ok := input[key]; ok {
			if s, ok := val.(string); ok {
				return s
			}
		}
		return ""
	}

	trigger.Title = getString("title")
	trigger.FilterStr = getString("filter_str")

	if trigger.FilterStr == "All Custom Events" {
		trigger.FilterStr = ""
	}

	// Set title if missing or empty
	if trigger.Title == "" {
		if trigger.FilterStr != "" {
			trigger.Title = trigger.FilterStr + " Postback"
		} else {
			trigger.Title = "All Custom Events"
		}
