//	@Summary		Agency Triggers
//	@Description	Get agency triggers by app ID and agency network IDs
//	@tags			Partners
//	@Accept			json
//	@Produce		json
//	@Param			appID				path		string							true	"App ID"
//	@Param			accountId			path		string							true	"Account ID"
//	@Param			agency_network_ids	query		string							true	"Comma separated list of agency network IDs"
//	@Success		200					{object}	models.BaseResponse{Data=[]int}	"List of agency network IDs"
//	@Failure		500					{object}	models.BaseResponse
//	@Router			/accounts/{accountId}/apps/{appID}/agency_triggers [get]
//
// ServeHTTP servers the HTTP request
func (h AgencyTriggers) ServeHTTP(w http.ResponseWriter, r *http.Request) {
	ctx := r.Context()
	vars := mux.Vars(r)
	appID := vars["appId"]

	agencyNetworkIDs := r.URL.Query().Get("agency_network_ids")

	if agencyNetworkIDs == "" {
		response.HandleError(ctx, w, http.StatusBadRequest, response.DebugLvl, "Missing agency network ids")
		return
	}

	ids := strings.Split(agencyNetworkIDs, ",")
	whereParams := map[string]any{"app_id": appID, "type": "install", "filter_agency_network": 0, "active": 1, "filter_network": ids}
	triggers, err := h.DB().GetPostbackTriggers(whereParams, "")
	if err != nil {
		response.HandleError(ctx, w, http.StatusInternalServerError, response.DebugLvl, "Failed to fetch agency partners", zap.Error(err))
		return
	}

	filterNetworks := make([]int, 0)
	for _, trigger := range triggers {
		filterNetworks = append(filterNetworks, trigger.FilterNetwork)
	}
	responseData := models.PartnersBaseResponse{
		Data: filterNetworks,
		Meta: &models.Meta{
			// Sql:            &query, // TODO: This can be added if needed
			PreparedValues: ids,
		},
		Success:  true,
		HTTPCode: http.StatusOK,
	}

	response.WriteResponse(ctx, w, responseData, http.StatusOK)
}
